INSERT INTO campaign_reference (id, state, office_level, category, question, question_variants, answer, source_url, source_name, last_verified_date, update_frequency, verification_method, scope, import_batch_id) VALUES
  ('1e03fe9fe42eb4b8', 'IN', '["federal"]', 'candidate_eligibility', 'Is there a U.S. Senate race in Indiana in 2026?', '["Are Todd Young or Jim Banks up for re-election in 2026?","When is the next US Senate election in IN?","Is the Indiana US Senate seat an open race?"]', 'No. There is no U.S. Senate election in Indiana in 2026. Senator Todd Young (Class 3) is next up for re-election in 2028, and Senator Jim Banks, who was elected in 2024, is next up in 2030.', 'https://www.in.gov/sos/elections/', 'Indiana Secretary of State – Elections', '2026-05-14', 'per_cycle', 'official_source_direct', 'Federal candidates and consultants', 'batch_2026-05-14T16-47-34_indiana_full_v1'),
  ('55e89fb880162400', 'IN', '["state"]', 'candidate_eligibility', 'Is Governor Mike Braun running for re-election in 2026?', '["Is the Indiana Governor''s seat open in 2026?","When is the next gubernatorial election in Indiana?","Indiana 2026 gubernatorial race status"]', 'No. Governor Mike Braun (R) was elected to a four-year term in November 2024 and is not on the ballot again until 2028. There is no gubernatorial election in Indiana in 2026.', 'https://www.in.gov/sos/elections/', 'Indiana Secretary of State – Elections', '2026-05-14', 'per_cycle', 'official_source_direct', 'Statewide candidates', 'batch_2026-05-14T16-47-34_indiana_full_v1'),
  ('99b4a4e913cc3ab7', 'IN', '["state"]', 'election_dates', 'Which statewide executive offices are up for election in Indiana in 2026?', '["Who is on the state ballot in IN in 2026?","Is the Attorney General up for reelection in Indiana?","Indiana statewide elections 2026"]', 'Three statewide executive offices are on the 2026 ballot: Secretary of State, Auditor of State (Comptroller), and Treasurer of State. The Attorney General (Todd Rokita) was elected in 2024 to a four-year term ending in January 2029 and is NOT on the 2026 ballot.', 'https://www.in.gov/sos/elections/', 'Indiana Secretary of State – Elections', '2026-05-14', 'per_cycle', 'official_source_direct', 'Statewide candidates', 'batch_2026-05-14T16-47-34_indiana_full_v1'),
  ('3935c8dd9bc5e0de', 'IN', '["state"]', 'ballot_access', 'How are major party candidates for Indiana Attorney General selected?', '["Is there a primary for Attorney General in IN?","Indiana Attorney General convention selection","How to run for AG in Indiana"]', 'In Indiana, major party candidates for Attorney General are NOT selected through a direct primary election. Instead, candidates are nominated by delegates at the respective state party conventions, and the chosen nominees then advance to the general election ballot.', 'https://www.in.gov/sos/elections/candidate-information/', 'Indiana Secretary of State – Candidate Information', '2026-05-14', 'static', 'official_source_direct', 'Statewide candidates and Strategists', 'batch_2026-05-14T16-47-34_indiana_full_v1'),
  ('3601044106124918', 'IN', '["federal"]', 'election_dates', 'How many U.S. House seats are up for election in Indiana in 2026?', '["Are all IN congressional districts on the ballot?","How many congressional districts does Indiana have?","Indiana US House elections 2026"]', 'All 9 of Indiana''s U.S. House districts are on the ballot in 2026. U.S. Representatives in Indiana, as in all states, serve two-year terms and are up for election every cycle.', 'https://www.in.gov/sos/elections/', 'Indiana Secretary of State – Elections', '2026-05-14', 'static', 'official_source_direct', 'Federal candidates', 'batch_2026-05-14T16-47-34_indiana_full_v1'),
  ('43377dfd9aa77c4e', 'IN', '["state"]', 'election_dates', 'How many Indiana state legislative seats are up for election in 2026?', '["Are all State Senate seats on the ballot in IN?","Indiana General Assembly elections 2026","Term lengths for Indiana state legislators"]', 'All 100 seats in the Indiana House of Representatives (which serve two-year terms) and exactly half (25) of the 50 seats in the Indiana State Senate (which serve staggered four-year terms) are up for election in 2026.', 'https://iga.in.gov/', 'Indiana General Assembly', '2026-05-14', 'static', 'official_source_direct', 'State Legislative candidates', 'batch_2026-05-14T16-47-34_indiana_full_v1'),
  ('5d6f3a900bf09605', 'IN', '["federal","state","county","municipal","judicial"]', 'election_dates', 'When are the 2026 primary and general elections in Indiana?', '["What date is the IN primary in 2026?","Indiana May primary date","When is Election Day 2026 in Indiana?"]', 'The Indiana Primary Election is scheduled for Tuesday, May 5, 2026. The General Election will be held concurrently with federal elections on Tuesday, November 3, 2026.', 'https://www.in.gov/sos/elections/', 'Indiana Secretary of State', '2026-05-14', 'per_cycle', 'official_source_direct', 'All candidates and voters', 'batch_2026-05-14T16-47-34_indiana_full_v1'),
  ('2538c7084494f812', 'IN', '["state"]', 'candidate_eligibility', 'What are the age and residency requirements to run for Governor or Lieutenant Governor in Indiana?', '["How old do you have to be to be IN Governor?","Gubernatorial candidate residency rules Indiana","Qualifications for Governor IN"]', 'Under Article 5 § 7 of the Indiana Constitution, a candidate for Governor or Lieutenant Governor must be at least 30 years old, a citizen of the United States for at least five years, and a resident of Indiana for at least five years immediately preceding the election.', 'https://iga.in.gov/laws/2023/ic/titles/99/articles/1/chapters/5', 'Indiana Constitution Article 5 § 7', '2026-05-14', 'static', 'statute_citation', 'Gubernatorial candidates', 'batch_2026-05-14T16-47-34_indiana_full_v1'),
  ('27f7cbe742809a7f', 'IN', '["state"]', 'candidate_eligibility', 'What are the term limits for the Governor of Indiana?', '["How many times can the Indiana Governor be re-elected?","Indiana Governor term limit rules","Article 5 Section 1 consecutive terms"]', 'Under Article 5 § 1 of the Indiana Constitution, the Governor serves a four-year term and is restricted from serving more than eight years in any twelve-year period, effectively establishing a limit of two consecutive terms.', 'https://iga.in.gov/laws/2023/ic/titles/99/articles/1/chapters/5', 'Indiana Constitution Article 5 § 1', '2026-05-14', 'static', 'statute_citation', 'Gubernatorial candidates and Strategists', 'batch_2026-05-14T16-47-34_indiana_full_v1'),
  ('d097d09092a031f8', 'IN', '["state"]', 'candidate_eligibility', 'What are the age and residency requirements to run for the Indiana State Senate?', '["How old to run for State Senate IN?","District residency for IN Senate candidates","Qualifications for Indiana State Senator"]', 'Under Article 4 § 7 of the Indiana Constitution, a candidate for the State Senate must be at least 25 years old, a citizen of the United States for at least two years, and an inhabitant of the state and their specific district for at least one year prior to the election.', 'https://iga.in.gov/laws/2023/ic/titles/99/articles/1/chapters/4', 'Indiana Constitution Article 4 § 7', '2026-05-14', 'static', 'statute_citation', 'State Senate candidates', 'batch_2026-05-14T16-47-34_indiana_full_v1'),
  ('1aad6ab3609bdafa', 'IN', '["state"]', 'candidate_eligibility', 'What are the age and residency requirements to run for the Indiana House of Representatives?', '["How old to run for State Representative IN?","District residency for IN House candidates","Qualifications for Indiana State Representative"]', 'Under Article 4 § 7 of the Indiana Constitution, a candidate for the State House of Representatives must be at least 21 years old, a citizen of the United States for at least two years, and an inhabitant of the state and the district they seek to represent for at least one year.', 'https://iga.in.gov/laws/2023/ic/titles/99/articles/1/chapters/4', 'Indiana Constitution Article 4 § 7', '2026-05-14', 'static', 'statute_citation', 'State House candidates', 'batch_2026-05-14T16-47-34_indiana_full_v1'),
  ('9e50bab1f07e2ae8', 'IN', '["federal"]', 'candidate_eligibility', 'What are the age and residency requirements to run for U.S. Senate in Indiana?', '["How old do you have to be to run for Senate?","Congressional age limit Indiana","US Senate qualifications"]', 'Under the U.S. Constitution, a candidate for the U.S. Senate must be at least 30 years old, a U.S. citizen for nine years, and an inhabitant of Indiana when elected.', 'https://www.in.gov/sos/elections/', 'Indiana Secretary of State / U.S. Constitution Art. I § 3', '2026-05-14', 'static', 'official_source_direct', 'U.S. Senate candidates', 'batch_2026-05-14T16-47-34_indiana_full_v1'),
  ('2ede175059fe4022', 'IN', '["federal"]', 'candidate_eligibility', 'What are the age and residency requirements to run for U.S. House in Indiana?', '["Do I have to live in the district to run for Congress in IN?","Congressional age limit Indiana","US House qualifications"]', 'Under the U.S. Constitution, a candidate for the U.S. House of Representatives must be at least 25 years old, a U.S. citizen for seven years, and an inhabitant of Indiana when elected. District residency is not a constitutional requirement.', 'https://www.in.gov/sos/elections/', 'Indiana Secretary of State / U.S. Constitution Art. I § 2', '2026-05-14', 'static', 'official_source_direct', 'U.S. House candidates', 'batch_2026-05-14T16-47-34_indiana_full_v1'),
  ('70a4e85996a13ceb', 'IN', '["state"]', 'candidate_eligibility', 'What are the qualifications and term limits for the Secretary of State, Auditor, and Treasurer in Indiana?', '["How many terms can the IN Secretary of State serve?","State Auditor eligibility Indiana","Treasurer 8 in 12 years rule"]', 'Candidates for Secretary of State, Auditor, and Treasurer must be registered voters of the state. Under Article 6 § 1 of the Indiana Constitution, they are elected to four-year terms and are term-limited, prohibited from serving more than eight years in any twelve-year period.', 'https://iga.in.gov/laws/2023/ic/titles/99/articles/1/chapters/6', 'Indiana Constitution Article 6 § 1', '2026-05-14', 'static', 'statute_citation', 'Statewide executive candidates', 'batch_2026-05-14T16-47-34_indiana_full_v1'),
  ('a59867975336aa89', 'IN', '["county"]', 'candidate_eligibility', 'What are the qualifications to run for County Sheriff in Indiana?', '["Does a sheriff need a law enforcement background in IN?","Indiana Sheriff requirements","Can anyone run for Sheriff in Indiana?"]', 'Under IC 36-2-13-2.5, Indiana has strict law enforcement background requirements for Sheriff. A candidate must have either 5 years of law enforcement experience, have served as a chief deputy, completed the law enforcement academy, or possess a college degree in criminal justice supplemented by relevant experience.', 'https://iga.in.gov/laws/2023/ic/titles/36#36-2-13-2.5', 'Indiana Code § 36-2-13-2.5', '2026-05-14', 'static', 'statute_citation', 'County-level candidates', 'batch_2026-05-14T16-47-34_indiana_full_v1'),
  ('ece06b1ea9c7eedc', 'IN', '["municipal"]', 'candidate_eligibility', 'What are the eligibility requirements to run for Mayor or City Council in Indiana?', '["How old do you have to be to be IN Mayor?","City council residency rules Indiana","Qualifications for Mayor IN"]', 'Under Indiana law, candidates for mayor or city council must be registered voters in the city and must have resided in the city (and their specific council district, if applicable) for at least one year immediately preceding the municipal election.', 'https://www.in.gov/sos/elections/candidate-information/', 'Indiana Secretary of State – Candidate Information', '2026-05-14', 'static', 'official_source_direct', 'Municipal candidates', 'batch_2026-05-14T16-47-34_indiana_full_v1'),
  ('4fbd09c0dd3c92b9', 'IN', '["municipal","special_district"]', 'candidate_eligibility', 'What are the qualifications to run for a local school board in Indiana?', '["How old do you have to be to run for IN School Board?","School board eligibility Indiana","Are school board elections partisan in IN?"]', 'School board elections in Indiana are strictly nonpartisan. To be eligible, a candidate must be at least 18 years old, a registered voter, and a resident of the school corporation (and their specific election district, if applicable) for at least one year prior to the election.', 'https://www.in.gov/sos/elections/candidate-information/', 'Indiana Secretary of State – Candidate Information', '2026-05-14', 'static', 'official_source_direct', 'School Board candidates', 'batch_2026-05-14T16-47-34_indiana_full_v1'),
  ('4ffc5c145ad14806', 'IN', '["municipal"]', 'candidate_eligibility', 'What is the role of a Township Trustee in Indiana?', '["What does an Indiana Township Trustee do?","How many townships are in Indiana?","Local government township elections IN"]', 'Indiana has 1,008 townships. Voters in each elect a Township Trustee and a 3-member Township Board to four-year terms. The trustee''s primary statutory duties include managing poor relief (township assistance) and overseeing fire protection services for unincorporated areas.', 'https://www.in.gov/sboa/about-us/townships/', 'Indiana State Board of Accounts', '2026-05-14', 'static', 'official_source_direct', 'Municipal and Township candidates', 'batch_2026-05-14T16-47-34_indiana_full_v1'),
  ('e556898c0164e08a', 'IN', '["federal","state","county","judicial"]', 'filing_requirements', 'What was the candidate filing deadline for the 2026 Indiana primary?', '["When did candidates have to file for the 2026 primary in Indiana?","Declaration of candidacy deadline 2026","Indiana February filing deadline"]', 'The deadline for major party candidates to file a declaration of candidacy for the May 2026 primary was February 6, 2026, at 12:00 noon.', 'https://www.in.gov/sos/elections/candidate-information/', 'Indiana Secretary of State – Candidate Information', '2026-05-14', 'per_cycle', 'official_source_direct', 'Major party candidates', 'batch_2026-05-14T16-47-34_indiana_full_v1'),
  ('8ebc9e3fa335a71c', 'IN', '["federal","state","county"]', 'filing_requirements', 'Does Indiana require candidates to pay a filing fee to run for office?', '["How much does it cost to run for office in IN?","Indiana candidate filing fees 2026","Do I have to pay to get on the ballot in Indiana?"]', 'No. Indiana does not charge a monetary filing fee for major party candidates to access the primary ballot. Instead, candidates file a declaration of candidacy (CAN-2 form) and, for certain statewide and federal offices, must submit signature petitions.', 'https://www.in.gov/sos/elections/candidate-information/', 'Indiana Secretary of State – Candidate Information', '2026-05-14', 'static', 'official_source_direct', 'All candidates', 'batch_2026-05-14T16-47-34_indiana_full_v1'),
  ('b2afcbaab5d0b2ff', 'IN', '["federal","state","county"]', 'filing_requirements', 'What is the filing deadline for independent and minor party candidates for the 2026 general election in Indiana?', '["When is the independent petition deadline in IN?","June 30 filing deadline Indiana","Minor party ballot access deadline"]', 'Independent and minor party candidates seeking to appear on the November 2026 general election ballot must file their petition of nomination with county voter registration offices for verification by 12:00 noon on June 30, 2026.', 'https://www.in.gov/sos/elections/candidate-information/', 'Indiana Secretary of State – Elections', '2026-05-14', 'per_cycle', 'official_source_direct', 'Independent and Minor Party candidates', 'batch_2026-05-14T16-47-34_indiana_full_v1'),
  ('d3401980a32448e1', 'IN', '["federal","state","county"]', 'ballot_access', 'What is the petition signature threshold for an independent candidate in Indiana?', '["How many signatures to run as an independent in IN?","IC 3-8-6 independent ballot access","2% signature rule Indiana"]', 'Under IC 3-8-6-3, an independent or minor party candidate must collect valid signatures equal to 2% of the total votes cast in the last election for Secretary of State within the specific election district the candidate seeks to represent.', 'https://iga.in.gov/laws/2023/ic/titles/3#3-8-6-3', 'Indiana Code § 3-8-6-3', '2026-05-14', 'static', 'statute_citation', 'Independent and Minor Party candidates', 'batch_2026-05-14T16-47-34_indiana_full_v1'),
  ('20edd2b31b713a50', 'IN', '["federal","state","county","municipal"]', 'filing_requirements', 'What is the procedure and deadline to run as a write-in candidate in Indiana?', '["Do write-in candidates have to register in IN?","How to run a write-in campaign in Indiana","July 6 write-in deadline"]', 'To have their votes counted, a write-in candidate must file a declaration of intent (CAN-3 form) with the appropriate election office. For the 2026 general election, this must be filed by 12:00 noon on July 6, 2026. Write-in names are not printed on the ballot.', 'https://www.in.gov/sos/elections/candidate-information/', 'Indiana Secretary of State – Candidate Information', '2026-05-14', 'per_cycle', 'official_source_direct', 'Write-in candidates', 'batch_2026-05-14T16-47-34_indiana_full_v1'),
  ('e4a3c9757f026c65', 'IN', '["federal","state"]', 'ballot_access', 'What is the threshold for a minor political party to gain automatic ballot access in Indiana?', '["Minor party status in IN","2% ballot access rule Indiana","How do third parties stay on the ballot in Indiana?"]', 'A political party retains automatic ballot access in Indiana if its candidate for Secretary of State received at least 2% of the total votes cast for that office in the most recent general election.', 'https://www.in.gov/sos/elections/', 'Indiana Secretary of State', '2026-05-14', 'static', 'official_source_direct', 'Minor party organizers', 'batch_2026-05-14T16-47-34_indiana_full_v1'),
  ('8a936ac3d1d80b44', 'IN', '["state"]', 'ballot_access', 'Do candidates for Governor and Lieutenant Governor run on a joint ticket in Indiana?', '["How is the Lieutenant Governor selected in IN?","Joint ticket for Governor and Lt. Governor","Do I vote separately for Governor and Lt. Gov?"]', 'Yes. Under Indiana Code § 3-8-1-9.5, candidates for Governor and Lieutenant Governor run together on a single joint ticket in the general election, meaning a voter casts a single vote for the pairing rather than selecting them individually.', 'https://iga.in.gov/laws/2023/ic/titles/3#3-8-1-9.5', 'Indiana Code § 3-8-1-9.5', '2026-05-14', 'static', 'statute_citation', 'Statewide candidates', 'batch_2026-05-14T16-47-34_indiana_full_v1'),
  ('f9bc8dd401a4554d', 'IN', '["federal","state","county","municipal"]', 'candidate_eligibility', 'Does Indiana have a sore loser law for independent candidates?', '["Can I run as an independent if I lose the primary in IN?","Indiana sore loser statute","Running for office after a primary defeat"]', 'Yes. Under Indiana Code § 3-8-1-5.5, a candidate who is defeated in a partisan primary or party convention is legally prohibited from running for the same office as an independent or minor party candidate in the subsequent general election.', 'https://iga.in.gov/laws/2023/ic/titles/3#3-8-1-5.5', 'Indiana Code § 3-8-1-5.5', '2026-05-14', 'static', 'statute_citation', 'Independent candidates and Strategists', 'batch_2026-05-14T16-47-34_indiana_full_v1'),
  ('0e386499a79d27a7', 'IN', '["state"]', 'election_dates', 'Who succeeds the Governor of Indiana in the event of a vacancy?', '["What happens if the IN Governor resigns?","Lieutenant Governor succession Indiana","Gubernatorial vacancy fill"]', 'Under Article 5 § 10 of the Indiana Constitution, if the office of the Governor becomes vacant due to death, resignation, or removal, the Lieutenant Governor immediately assumes the office of Governor for the remainder of the unexpired term.', 'https://iga.in.gov/laws/2023/ic/titles/99/articles/1/chapters/5', 'Indiana Constitution Article 5 § 10', '2026-05-14', 'static', 'statute_citation', 'Statewide officials', 'batch_2026-05-14T16-47-34_indiana_full_v1'),
  ('46192d6c01df400a', 'IN', '["state"]', 'election_dates', 'How are mid-term vacancies in the Indiana General Assembly filled?', '["Special election for State Assembly IN","How is a vacant state senate seat filled in Indiana?","Legislative vacancy caucus procedure IN"]', 'Legislative vacancies in Indiana are NOT filled by a special election. Under Indiana Code § 3-13-5-1, a mid-term vacancy in the State Senate or State House is filled by a caucus of precinct committeepersons from the same political party that previously held the vacated seat.', 'https://iga.in.gov/laws/2023/ic/titles/3#3-13-5-1', 'Indiana Code § 3-13-5-1', '2026-05-14', 'static', 'statute_citation', 'State Legislative candidates and Political Parties', 'batch_2026-05-14T16-47-34_indiana_full_v1'),
  ('3b3629d1b0cb0c4d', 'IN', '["federal","state","county","municipal","judicial"]', 'voter_interaction', 'What is the voter registration deadline in Indiana?', '["When is the last day to register to vote in IN?","29-day registration rule Indiana","Voter registration cutoff IN"]', 'The deadline to register to vote in Indiana is 29 days before the election. For the November 2026 general election, this deadline will fall on October 5, 2026.', 'https://www.in.gov/sos/elections/voter-information/register-to-vote/', 'Indiana Secretary of State – Voter Registration', '2026-05-14', 'static', 'official_source_direct', 'Unregistered voters', 'batch_2026-05-14T16-47-34_indiana_full_v1'),
  ('3f72d9614637dfc8', 'IN', '["federal","state","county","municipal","judicial"]', 'voter_interaction', 'Does Indiana have an online voter registration portal?', '["Can I register to vote online in IN?","IndianaVoters.com","Electronic voter registration Indiana"]', 'Yes. Eligible Indiana citizens with a valid state driver''s license or state-issued ID can register to vote or update their registration online through the IndianaVoters.in.gov portal.', 'https://indianavoters.in.gov/', 'Indiana Voter Portal', '2026-05-14', 'static', 'official_source_direct', 'Unregistered voters', 'batch_2026-05-14T16-47-34_indiana_full_v1'),
  ('2e4603c461ec6a48', 'IN', '["federal","state","county","municipal","judicial"]', 'voter_interaction', 'Does Indiana allow same-day voter registration at polling places?', '["Can I register to vote at the polls in Indiana?","Same-day registration rules IN","Election day registration Indiana"]', 'No. Indiana does not offer same-day voter registration. Eligible citizens must register to vote by the 29-day statutory deadline prior to the election to cast a ballot.', 'https://www.in.gov/sos/elections/voter-information/register-to-vote/', 'Indiana Secretary of State – Voter Registration', '2026-05-14', 'static', 'official_source_direct', 'Unregistered voters', 'batch_2026-05-14T16-47-34_indiana_full_v1'),
  ('dd13c5b30a0baba8', 'IN', '["federal","state","county","municipal","judicial"]', 'voter_interaction', 'How long is the early voting window for in-person voting in Indiana?', '["When does early voting start in IN?","28-day early voting rule Indiana","In-person absentee duration IN"]', 'Indiana provides early in-person voting (often referred to statutorily as in-person absentee voting). The early voting period officially begins 28 days before the election at the county election board office (typically the circuit court clerk''s office), with additional satellite locations determined by individual counties.', 'https://www.in.gov/sos/elections/voter-information/ways-to-vote/early-voting-in-person/', 'Indiana Secretary of State – Early Voting', '2026-05-14', 'static', 'official_source_direct', 'All voters and GOTV operations', 'batch_2026-05-14T16-47-34_indiana_full_v1'),
  ('dd8a8e7edd8dc24e', 'IN', '["federal","state","county","municipal","judicial"]', 'voter_interaction', 'Does Indiana allow no-excuse absentee voting by mail?', '["Can anyone vote by mail in Indiana?","Do I need an excuse for an absentee ballot in IN?","No-excuse absentee rules IN"]', 'No. Indiana strictly requires an excuse to vote absentee by mail. Under Indiana Code § 3-11-10-24, voters must meet one of specific criteria (e.g., 65 or older, confined due to illness, or working the entire 12 hours polls are open) to request a mail-in absentee ballot.', 'https://www.in.gov/sos/elections/voter-information/ways-to-vote/absentee-voting/', 'Indiana Secretary of State – Absentee Voting', '2026-05-14', 'static', 'official_source_direct', 'All voters and GOTV operations', 'batch_2026-05-14T16-47-34_indiana_full_v1'),
  ('d4855ecb35842d85', 'IN', '["federal","state","county","municipal","judicial"]', 'voter_interaction', 'What is the deadline to request a mail-in absentee ballot in Indiana?', '["When is the last day to ask for a mail ballot in IN?","Absentee application deadline Indiana","How many days before the election must I request an absentee ballot?"]', 'To vote by mail, the county election board must receive a voter''s absentee ballot application no later than 11:59 p.m. on the 12th day before the election.', 'https://www.in.gov/sos/elections/voter-information/ways-to-vote/absentee-voting/', 'Indiana Secretary of State – Absentee Voting', '2026-05-14', 'static', 'official_source_direct', 'Absentee voters', 'batch_2026-05-14T16-47-34_indiana_full_v1'),
  ('bd10b519f425cfeb', 'IN', '["federal","state","county","municipal","judicial"]', 'election_dates', 'What is the deadline for an absentee ballot to be received and counted in Indiana?', '["When is my absentee ballot due in IN?","Indiana mail ballot postmark rule","Election Day 6pm ballot receipt"]', 'To be counted, an absentee ballot must be physically received by the county election board by 6:00 p.m. on Election Day. Indiana does not have a postmark grace period for mail-in ballots.', 'https://www.in.gov/sos/elections/voter-information/ways-to-vote/absentee-voting/', 'Indiana Secretary of State – Absentee Voting', '2026-05-14', 'static', 'official_source_direct', 'Absentee voters and Campaigns', 'batch_2026-05-14T16-47-34_indiana_full_v1'),
  ('4770586d507c6016', 'IN', '["federal","state","county","municipal","judicial"]', 'voter_interaction', 'Can I vote early in person on Election Day in Indiana?', '["Early voting on Election Day IN","Does early voting continue through Tuesday in Indiana?","When does in-person absentee voting end?"]', 'No. In-person early voting concludes at noon on the Monday immediately prior to Election Day. On Election Day itself, voters may only cast ballots at their assigned polling place or an established vote center during the regular 6:00 a.m. to 6:00 p.m. window.', 'https://www.in.gov/sos/elections/voter-information/ways-to-vote/early-voting-in-person/', 'Indiana Secretary of State – Early Voting', '2026-05-14', 'static', 'official_source_direct', 'All voters and GOTV operations', 'batch_2026-05-14T16-47-34_indiana_full_v1'),
  ('0e80e2765627684a', 'IN', '["federal","state","county","municipal","judicial"]', 'voter_interaction', 'What are the voting hours on Election Day in Indiana?', '["When do polls open and close in IN?","Indiana election day voting hours","What time do polls close on Election Day?"]', 'Polling places in Indiana are open from 6:00 a.m. to 6:00 p.m. local time on Election Day. Any voter who is physically in line at the polling place by 6:00 p.m. must be permitted to cast their ballot.', 'https://www.in.gov/sos/elections/voter-information/', 'Indiana Secretary of State – Voter Information', '2026-05-14', 'static', 'official_source_direct', 'All voters', 'batch_2026-05-14T16-47-34_indiana_full_v1'),
  ('630e328484ab3ea2', 'IN', '["federal","state","county","municipal","judicial"]', 'voter_interaction', 'Is a photo ID required to vote at the polls in Indiana?', '["Indiana voter ID laws","Poll ID requirements Indiana","Do I need my driver''s license to vote in IN?"]', 'Yes. Indiana requires a valid government-issued photo ID to vote in person. The state''s strict photo ID requirement was famously upheld by the U.S. Supreme Court in the 2008 landmark case Crawford v. Marion County Election Board.', 'https://www.in.gov/sos/elections/voter-information/photo-id-law/', 'Indiana Secretary of State – Photo ID Law', '2026-05-14', 'static', 'official_source_direct', 'All voters', 'batch_2026-05-14T16-47-34_indiana_full_v1'),
  ('d64a352a3d316ead', 'IN', '["federal","state","county","municipal","judicial"]', 'voter_interaction', 'What forms of photo ID are acceptable for voting in Indiana post-SB 10?', '["Valid ID list Indiana voting","Can I use a passport to vote in IN?","What counts as photo ID in Indiana?"]', 'To be valid, an ID must display the voter''s photo, name (matching the registration record), an expiration date (either current or expired after the last general election), and be issued by the State of Indiana or the U.S. government. Examples include an Indiana driver''s license, U.S. passport, military ID, state ID card, or Indiana National Guard ID.', 'https://www.in.gov/sos/elections/voter-information/photo-id-law/', 'Indiana Secretary of State – Photo ID Law', '2026-05-14', 'static', 'official_source_direct', 'All voters', 'batch_2026-05-14T16-47-34_indiana_full_v1'),
  ('66081a1b0c54f04c', 'IN', '["federal","state","county","municipal","judicial"]', 'voter_interaction', 'Can college students use their student ID to vote in Indiana?', '["Is a college ID valid for voting in IN?","SB 10 student ID ban litigation","Can I use my university ID to vote?"]', 'Currently, no, but the law is under active litigation. In April 2025, Governor Braun signed SB 10, banning the use of all student IDs for voting. A federal judge issued a preliminary injunction on April 14, 2026, but the 7th Circuit stayed the injunction on April 21, 2026. Therefore, student IDs are invalid for voting in 2026 pending further appeals.', 'https://www.in.gov/sos/elections/voter-information/photo-id-law/', 'Indiana Secretary of State – Photo ID Law (Volatile Litigation)', '2026-05-14', 'volatile', 'secondary_source', 'Student voters', 'batch_2026-05-14T16-47-34_indiana_full_v1'),
  ('554325f99c61b331', 'IN', '["federal","state","county","municipal","judicial"]', 'voter_interaction', 'What is the provisional ballot process for a voter who forgets their photo ID in Indiana?', '["Indiana provisional ballot rules","Voting if my ID is missing at the polls IN","Affidavit of indigency voter ID exception"]', 'A voter lacking an acceptable photo ID can cast a provisional ballot. To have it counted, the voter must visit the county election board by noon on the second Friday following the election to provide valid ID. If the voter is indigent or has a religious objection to being photographed, they may sign an affidavit of exemption instead.', 'https://www.in.gov/sos/elections/voter-information/photo-id-law/', 'Indiana Secretary of State – Photo ID Law', '2026-05-14', 'static', 'official_source_direct', 'Voters and Poll Watchers', 'batch_2026-05-14T16-47-34_indiana_full_v1'),
  ('a3bcf80b68d02476', 'IN', '["federal","state","county","municipal","judicial"]', 'voter_interaction', 'What is the electioneering buffer zone at Indiana polling places?', '["How close to the door can I campaign in IN?","50-foot chute rule Indiana voting","Campaign signs at polling places IN"]', 'Indiana enforces a 50-foot electioneering buffer zone, measured from the entrance of the ''chute'' (the path leading to the entrance of the polls). No electioneering or distribution of campaign materials is permitted within this area.', 'https://iga.in.gov/laws/2023/ic/titles/3#3-14-3-16', 'Indiana Code § 3-14-3-16', '2026-05-14', 'static', 'statute_citation', 'Campaigns and Poll Workers', 'batch_2026-05-14T16-47-34_indiana_full_v1'),
  ('4b4cdc829cf701c6', 'IN', '["federal","state","county","municipal","judicial"]', 'voter_interaction', 'What are the criminal penalties for voter intimidation in Indiana?', '["Is voter intimidation illegal in IN?","Indiana Code 3-14-3-21 penalties","Coercing voters in Indiana"]', 'Under Indiana Code § 3-14-3-21, utilizing force, threats, or intimidation to influence a person to vote or refrain from voting, or interfering with their free exercise of the franchise, constitutes a Level 6 felony.', 'https://iga.in.gov/laws/2023/ic/titles/3#3-14-3-21', 'Indiana Code § 3-14-3-21', '2026-05-14', 'static', 'statute_citation', 'All voters and Campaigns', 'batch_2026-05-14T16-47-34_indiana_full_v1'),
  ('a19c53db392d5a26', 'IN', '["federal","state","county","municipal"]', 'candidate_eligibility', 'Can a person with a felony conviction vote in Indiana?', '["Felon voting rights IN","Voting post-incarceration rules Indiana","Can I vote while on probation in IN?"]', 'Yes. In Indiana, voting rights are automatically restored immediately upon a person''s release from incarceration. Individuals who are serving time on probation, parole, or home detention are fully eligible to vote, provided they re-register.', 'https://www.in.gov/sos/elections/voter-information/register-to-vote/', 'Indiana Secretary of State – Voter Registration', '2026-05-14', 'static', 'official_source_direct', 'All eligible citizens', 'batch_2026-05-14T16-47-34_indiana_full_v1'),
  ('692841ef0cb22fe7', 'IN', '["federal","state","county","municipal","judicial"]', 'voter_interaction', 'How are voter registration lists maintained in Indiana?', '["Indiana voter roll purges","NVRA list maintenance IN","Crosscheck voter list cleaning"]', 'Voter lists are maintained in compliance with the National Voter Registration Act (NVRA). Indiana runs regular data crosschecks to identify voters who have moved or died. Inactive voters are removed if they fail to respond to a mail notice and subsequently do not vote in two consecutive federal general elections.', 'https://www.in.gov/sos/elections/voter-information/', 'Indiana Secretary of State – Voter Information', '2026-05-14', 'static', 'official_source_direct', 'Election officials and campaigns', 'batch_2026-05-14T16-47-34_indiana_full_v1'),
  ('c17bb5ff16307770', 'IN', '["federal","state","county","municipal","judicial"]', 'voter_interaction', 'How do overseas and military voters cast their ballots in Indiana?', '["UOCAVA voting in IN","Can military personnel vote by email in Indiana?","Absentee voting from abroad"]', 'Under UOCAVA rules, Indiana allows military and overseas voters to request and return absentee ballots via mail, email, or fax. These requests must be processed promptly, and ballots sent via email or fax must be received by 6:00 p.m. on Election Day.', 'https://www.in.gov/sos/elections/voter-information/ways-to-vote/military-and-overseas-voters/', 'Indiana Secretary of State – Military and Overseas Voters', '2026-05-14', 'static', 'official_source_direct', 'Military and Overseas voters', 'batch_2026-05-14T16-47-34_indiana_full_v1'),
  ('f472b783dc7e0cd0', 'IN', '["state","county","municipal","judicial"]', 'finance_ethics', 'Who enforces campaign finance rules in Indiana?', '["Does the Secretary of State handle campaign finance in IN?","Jurisdiction of the Indiana Election Division","Where do I file campaign finance reports in Indiana?"]', 'Campaign finance regulations are administered jointly by the Indiana Election Division and the Indiana Secretary of State. The Election Division oversees the filing, auditing, and enforcement of campaign finance reports for state-level candidates and PACs.', 'https://www.in.gov/sos/elections/campaign-finance/', 'Indiana Secretary of State – Campaign Finance', '2026-05-14', 'static', 'official_source_direct', 'Candidates and Campaign Treasurers', 'batch_2026-05-14T16-47-34_indiana_full_v1'),
  ('48fc6117598b7a12', 'IN', '["state","county","municipal","judicial"]', 'finance_ethics', 'What are the individual contribution limits for state campaigns in Indiana?', '["How much can an individual give to a candidate in IN?","Indiana individual donation limits","Are there campaign contribution caps for individuals in Indiana?"]', 'Indiana has no contribution limits for individuals giving to state and local candidates. Individuals and PACs may contribute unlimited amounts directly to candidate campaigns and political parties.', 'https://www.in.gov/sos/elections/campaign-finance/', 'Indiana Secretary of State – Campaign Finance', '2026-05-14', 'static', 'official_source_direct', 'Candidates and Donors', 'batch_2026-05-14T16-47-34_indiana_full_v1'),
  ('e5afbe4fe51020f2', 'IN', '["state","county","municipal","judicial"]', 'finance_ethics', 'What is the full annual aggregate cap for corporate and union contributions in Indiana?', '["IN $22,000 corporate contribution limit","How are corporate donations capped in Indiana?","Labor union donation limits categories"]', 'While individuals give unlimited amounts, corporations and labor unions are strictly capped at an aggregate of $22,000 per calendar year across specific categories: $5k to statewide candidates, $5k to state party committees, $2k to State Senate candidates, $2k to State House candidates, $2k to Senate caucuses, $2k to House caucuses, $2k to local candidates, and $2k to other party committees.', 'https://iga.in.gov/laws/2023/ic/titles/3#3-9-2-4', 'Indiana Code § 3-9-2-4', '2026-05-14', 'static', 'statute_citation', 'Corporations, Unions, and Campaign Treasurers', 'batch_2026-05-14T16-47-34_indiana_full_v1'),
  ('b72bdcd54edfca75', 'IN', '["state","county","municipal"]', 'finance_ethics', 'Are LLCs subject to the same contribution limits as corporations in Indiana?', '["Can LLCs give unlimited money in IN?","Indiana partnership campaign donation rules","LLC contribution limits Indiana"]', 'No. Under Indiana campaign finance interpretations, Limited Liability Companies (LLCs) and partnerships are treated as individual entities. Unlike corporations, they are NOT subject to the $22,000 aggregate cap and can contribute unlimited amounts.', 'https://www.in.gov/sos/elections/campaign-finance/', 'Indiana Secretary of State – Campaign Finance', '2026-05-14', 'static', 'official_source_direct', 'LLCs, Partnerships, and Campaign Treasurers', 'batch_2026-05-14T16-47-34_indiana_full_v1')
INSERT INTO campaign_reference (id, state, office_level, category, question, question_variants, answer, source_url, source_name, last_verified_date, update_frequency, verification_method, scope, import_batch_id) VALUES
  ('8f9505f6e893eff1', 'IN', '["state"]', 'finance_ethics', 'What is the sessional blackout rule for campaign contributions in Indiana?', '["Lobbyist session ban IN","When are contributions banned for state reps?","Sessional blackout campaign finance Indiana"]', 'Under IC 3-9-2-12, state legislators and statewide candidates cannot accept contributions during the ''long'' legislative session from January until sine die adjournment, but this ONLY applies in odd-numbered years. Because 2026 is an even-numbered year, the sessional blackout does NOT apply.', 'https://iga.in.gov/laws/2023/ic/titles/3#3-9-2-12', 'Indiana Code § 3-9-2-12', '2026-05-14', 'static', 'statute_citation', 'State candidates, Lobbyists, and PACs', 'batch_2026-05-14T16-47-34_indiana_full_v1'),
  ('3de2788c729510e2', 'IN', '["state","county","municipal"]', 'finance_ethics', 'What is the threshold for registering a candidate campaign committee in Indiana?', '["When do I have to register a campaign committee in IN?","Candidate committee registration dollar limit","How much can I spend before filing a committee?"]', 'A candidate must file a statement of organization to register their principal campaign committee no later than noon ten days after receiving contributions or making expenditures exceeding $100.', 'https://iga.in.gov/laws/2023/ic/titles/3#3-9-1-3', 'Indiana Code § 3-9-1-3', '2026-05-14', 'static', 'statute_citation', 'All state and local candidates', 'batch_2026-05-14T16-47-34_indiana_full_v1'),
  ('6c599a2362cd215c', 'IN', '["state","county","municipal"]', 'finance_ethics', 'What is the threshold for registering a Political Action Committee (PAC) in Indiana?', '["When does an independent group have to file in IN?","PAC registration threshold Indiana","How much money requires a PAC registration?"]', 'Any organization or group proposing to influence an election in Indiana must register as a Political Action Committee (PAC) within ten days after accepting contributions or making expenditures exceeding $100.', 'https://iga.in.gov/laws/2023/ic/titles/3#3-9-1-3', 'Indiana Code § 3-9-1-3', '2026-05-14', 'static', 'statute_citation', 'PACs and Super PACs', 'batch_2026-05-14T16-47-34_indiana_full_v1'),
  ('eb6bba9cb6aaddf6', 'IN', '["state","county","municipal"]', 'finance_ethics', 'What are the standard campaign finance reporting periods in Indiana?', '["When are campaign finance reports due in IN?","Reporting calendar specifics Indiana","Periodic campaign filing dates IN"]', 'Registered candidate committees in Indiana must file periodic campaign finance reports. In an election year, standard reports are due pre-primary (in April), pre-election (in October), and a final annual report is due in January of the following year.', 'https://www.in.gov/sos/elections/campaign-finance/', 'Indiana Secretary of State – Campaign Finance', '2026-05-14', 'static', 'official_source_direct', 'Campaign Treasurers', 'batch_2026-05-14T16-47-34_indiana_full_v1'),
  ('24fddac54792783e', 'IN', '["state","county","municipal"]', 'finance_ethics', 'What is the itemized disclosure threshold for individual campaign contributions in Indiana?', '["When do I have to list a donor''s name in IN?","Campaign contribution disclosure limit Indiana","Indiana $100 donation rule"]', 'Candidate committees and PACs must itemize and disclose the name and address of each contributor who gives more than $100 in aggregate during a calendar year. For regular party committees, the itemization threshold is $200.', 'https://iga.in.gov/laws/2023/ic/titles/3#3-9-5-14', 'Indiana Code § 3-9-5-14', '2026-05-14', 'static', 'statute_citation', 'Campaign Treasurers', 'batch_2026-05-14T16-47-34_indiana_full_v1'),
  ('0d875b693d060b99', 'IN', '["state","county","municipal","judicial"]', 'finance_ethics', 'Does Indiana prohibit the personal use of campaign funds?', '["Can I use campaign money for my mortgage IN?","Personal use prohibition IN campaign finance","IC 3-9-3-4 restrictions"]', 'Yes. Under Indiana Code § 3-9-3-4, campaign funds cannot be used for the personal benefit of the candidate or any other person. Funds must be used strictly for reasonable campaign expenses or political activity.', 'https://iga.in.gov/laws/2023/ic/titles/3#3-9-3-4', 'Indiana Code § 3-9-3-4', '2026-05-14', 'static', 'statute_citation', 'Candidates and Treasurers', 'batch_2026-05-14T16-47-34_indiana_full_v1'),
  ('b65fe093215a60bb', 'IN', '["state","county","municipal"]', 'finance_ethics', 'What is the penalty for filing a campaign finance report late in Indiana?', '["IN late filing fines","Campaign finance penalty schedule Indiana","Late reporting fines IN"]', 'Failure to file a timely campaign finance report in Indiana incurs an automatic civil penalty of $50 per day for each day the report is late, up to a maximum penalty of $1,000, plus any investigative costs.', 'https://www.in.gov/sos/elections/campaign-finance/', 'Indiana Secretary of State – Campaign Finance', '2026-05-14', 'static', 'official_source_direct', 'Campaign Treasurers', 'batch_2026-05-14T16-47-34_indiana_full_v1'),
  ('23b068ca0a4a3db1', 'IN', '["federal","state","county","municipal"]', 'finance_ethics', 'What are the disclaimer requirements for political advertising in Indiana?', '["Do mailers need an ''Ad paid for by'' disclaimer IN?","Attribution statements Indiana","Yard sign disclaimer requirements"]', 'Any published or broadcast political material designed to influence an election must include an explicit ''Paid for by'' attribution statement indicating the name of the person or committee who paid for the communication. There are exemptions for small items like buttons or bumper stickers.', 'https://www.in.gov/sos/elections/campaign-finance/', 'Indiana Secretary of State – Campaign Finance', '2026-05-14', 'static', 'official_source_direct', 'All Campaigns and Printers', 'batch_2026-05-14T16-47-34_indiana_full_v1'),
  ('9aa2d3385bf69240', 'IN', '["judicial"]', 'election_dates', 'Are judges on the Indiana Supreme Court elected or appointed?', '["How are Supreme Court justices selected in IN?","Missouri Plan Indiana","Judicial selection process Indiana appellate courts"]', 'Justices on the Indiana Supreme Court and judges on the Court of Appeals are selected via a merit-based ''Missouri Plan'' system. The Governor appoints a nominee from a list provided by the Judicial Nominating Commission. After serving for a period, these justices then face periodic yes/no retention elections.', 'https://www.in.gov/courts/about/retention/', 'Indiana Judicial Branch – Retention', '2026-05-14', 'static', 'official_source_direct', 'Judicial candidates and nominees', 'batch_2026-05-14T16-47-34_indiana_full_v1'),
  ('a566296547fc5125', 'IN', '["judicial"]', 'election_dates', 'What is the term length for an Indiana Supreme Court Justice after winning a retention election?', '["How long do Supreme Court justices serve in IN?","Indiana Supreme Court retention elections","Appellate court term length Indiana"]', 'After an initial appointment and standing for a first retention election (held at the first statewide general election after serving two full years), a retained Indiana Supreme Court justice or Court of Appeals judge serves a 10-year term before facing another retention vote.', 'https://www.in.gov/courts/about/retention/', 'Indiana Judicial Branch – Retention', '2026-05-14', 'static', 'official_source_direct', 'Judicial candidates', 'batch_2026-05-14T16-47-34_indiana_full_v1'),
  ('8c312801e6b3c162', 'IN', '["judicial"]', 'election_dates', 'Are Indiana trial court judges elected in partisan elections?', '["Circuit Court selection mechanism Indiana","Are trial judges partisan in IN?","Superior Court elections IN"]', 'The vast majority of trial court judges (Circuit and Superior courts) in Indiana are elected in partisan elections to six-year terms. However, there are significant exceptions: a few specific counties (such as Lake, Marion, Allen, St. Joseph, and Vanderburgh) use merit selection or nonpartisan elections.', 'https://www.in.gov/courts/about/', 'Indiana Judicial Branch', '2026-05-14', 'static', 'official_source_direct', 'Judicial candidates', 'batch_2026-05-14T16-47-34_indiana_full_v1'),
  ('2c6dc5c12caa99cf', 'IN', '["judicial"]', 'election_dates', 'How is the Indiana Tax Court judge selected?', '["Is the Tax Court elected in Indiana?","Who appoints the Tax Court judge IN?","Tax Court selection mechanism"]', 'The sole judge of the Indiana Tax Court is selected using the same merit-based system as the appellate courts. The Governor appoints the judge from a list of nominees provided by the Judicial Nominating Commission, followed by periodic 10-year retention elections.', 'https://www.in.gov/courts/about/retention/', 'Indiana Judicial Branch – Retention', '2026-05-14', 'static', 'official_source_direct', 'Judicial candidates and Legal Counsel', 'batch_2026-05-14T16-47-34_indiana_full_v1'),
  ('ea216906fece427d', 'IN', '["judicial"]', 'election_dates', 'Are Small Claims Court judges elected in Indiana?', '["Marion County Small Claims Court elections","Are small claims judges partisan in IN?","Township small claims courts"]', 'Marion County (Indianapolis) uniquely operates township-based Small Claims Courts. Judges for these specific courts are elected in partisan elections by the voters within their respective townships to serve four-year terms.', 'https://www.in.gov/courts/about/', 'Indiana Judicial Branch', '2026-05-14', 'static', 'official_source_direct', 'Judicial candidates in Marion County', 'batch_2026-05-14T16-47-34_indiana_full_v1'),
  ('35e138718837bd37', 'IN', '["federal","state"]', 'redistricting', 'Who draws the congressional and legislative maps in Indiana?', '["Indiana redistricting commission","How are districts drawn in Indiana?","Does Indiana use an independent commission for redistricting?"]', 'In Indiana, the General Assembly (the state legislature) is solely responsible for drawing and approving both congressional and state legislative district maps. The 2021 redistricting cycle was controlled by the Republican supermajority without the use of an independent commission.', 'https://iga.in.gov/', 'Indiana General Assembly', '2026-05-14', 'static', 'official_source_direct', 'Federal and State Legislative candidates', 'batch_2026-05-14T16-47-34_indiana_full_v1'),
  ('3c3cb1c2e6533f25', 'IN', '["federal"]', 'redistricting', 'How many congressional districts does Indiana have for the 2026 cycle?', '["Number of US House seats in IN","Indiana congressional apportionment","How many electoral votes does Indiana have?"]', 'Based on the post-2020 census apportionment, Indiana retained its 9 U.S. House districts, granting the state a total of 11 Electoral College votes for presidential elections.', 'https://www.in.gov/sos/elections/', 'Indiana Secretary of State', '2026-05-14', 'static', 'official_source_direct', 'U.S. House candidates', 'batch_2026-05-14T16-47-34_indiana_full_v1'),
  ('ac9bad2e95cb0610', 'IN', '["federal","state"]', 'redistricting', 'Did the 2021 Indiana redistricting maps survive court challenges?', '["Indiana redistricting litigation","Were the 2021 maps struck down in IN?","Gerrymandering lawsuits Indiana"]', 'Yes. Unlike maps in several surrounding states that faced prolonged litigation or were overturned, the maps drawn by the Indiana General Assembly during the 2021 redistricting cycle stood without successful federal or state court intervention.', 'https://iga.in.gov/', 'Indiana General Assembly', '2026-05-14', 'static', 'official_source_direct', 'All federal and state candidates', 'batch_2026-05-14T16-47-34_indiana_full_v1'),
  ('fc7e36892fd5d182', 'IN', '["county"]', 'election_dates', 'How many counties are in Indiana and who administers local elections?', '["How many counties in IN?","County auditor role in Indiana elections","Who runs local elections in IN?"]', 'Indiana is divided into 92 counties. Election administration is largely conducted at the county level by the bipartisan county election board and the circuit court clerk.', 'https://www.in.gov/sos/elections/', 'Indiana Secretary of State – Elections', '2026-05-14', 'static', 'official_source_direct', 'Candidates and Local Officials', 'batch_2026-05-14T16-47-34_indiana_full_v1'),
  ('974b5f081e290b64', 'IN', '["county"]', 'election_dates', 'Are county-level executive offices partisan in Indiana?', '["Is the sheriff race partisan in IN?","Are county auditors partisan in Indiana?","Indiana county office election structure"]', 'Yes. In Indiana, county constitutional officers—including the Sheriff, Prosecutor, Assessor, Auditor, Recorder, Treasurer, Surveyor, and Coroner—are elected in partisan contests to serve four-year terms.', 'https://www.in.gov/sos/elections/', 'Indiana Secretary of State', '2026-05-14', 'static', 'official_source_direct', 'County-level candidates', 'batch_2026-05-14T16-47-34_indiana_full_v1'),
  ('941d856c496dd637', 'IN', '["county"]', 'election_dates', 'What is the difference between the County Commissioners and County Council in Indiana?', '["County legislative body Indiana","Who sets the county budget in IN?","Executive vs fiscal branch county level"]', 'Indiana utilizes a divided county government structure. The Board of County Commissioners acts as the executive and administrative body, while the County Council acts as the fiscal branch, approving the budget and levying taxes. Both are elected, partisan positions.', 'https://www.in.gov/sboa/about-us/counties/', 'Indiana State Board of Accounts', '2026-05-14', 'static', 'official_source_direct', 'County-level candidates', 'batch_2026-05-14T16-47-34_indiana_full_v1'),
  ('6d943d1ecf69180c', 'IN', '["municipal"]', 'election_dates', 'What is the structure of a Township Board in Indiana?', '["How many members on an Indiana township board?","Township government structure IN","Elected township officials"]', 'In addition to the executive Township Trustee, voters in each of Indiana''s 1,008 townships elect a three-member Township Board (or a 7-member board in Marion County). They serve four-year terms and act as the legislative and fiscal body for the township.', 'https://www.in.gov/sboa/about-us/townships/', 'Indiana State Board of Accounts', '2026-05-14', 'static', 'official_source_direct', 'Township candidates', 'batch_2026-05-14T16-47-34_indiana_full_v1'),
  ('5b941eda208d82d7', 'IN', '["federal","state","county","municipal"]', 'voter_interaction', 'Does Indiana allow straight-ticket voting?', '["Can I vote a straight party ticket in IN?","Straight-party option Indiana ballot","Does voting straight ticket cover nonpartisan races?"]', 'Yes. Indiana is one of the few remaining states that allows straight-ticket voting. A voter can select a political party at the top of the ballot to automatically vote for all of that party''s partisan candidates, though they must still manually vote in nonpartisan races like school boards or judicial retention.', 'https://www.in.gov/sos/elections/voter-information/', 'Indiana Secretary of State – Voter Information', '2026-05-14', 'static', 'official_source_direct', 'Voters and Strategists', 'batch_2026-05-14T16-47-34_indiana_full_v1'),
  ('1274f53d5077b49a', 'IN', '["state","county","municipal","judicial"]', 'recall_rules', 'Can voters recall the Governor or state legislators in Indiana?', '["Statewide recall mechanism IN","How to recall a state official in Indiana","Does Indiana allow for the removal of politicians by petition?"]', 'No. Indiana does not have a constitutional or statutory mechanism for the recall of statewide officials, state legislators, or local elected officials by citizen petition. Removal of public officials is handled via impeachment or specific statutory removal proceedings for misconduct.', 'https://www.in.gov/sos/elections/', 'Indiana Secretary of State', '2026-05-14', 'static', 'official_source_direct', 'Voters and Campaigns', 'batch_2026-05-14T16-47-34_indiana_full_v1'),
  ('9e93442b7c46ccd6', 'IN', '["state","county","municipal"]', 'finance_ethics', 'Does the Federal Hatch Act apply to state and local employees in Indiana?', '["Can Indiana state employees run for office?","Hatch act applicability to IN civil servants","Are local government workers banned from politics?"]', 'The Federal Hatch Act restricts the political activities of state and local government employees only if their principal employment is in connection with an activity financed in whole or in part by federal loans or grants. Standard state employees funded solely by state revenues are not subject to the federal restriction.', 'https://osc.gov/Services/HatchAct/StateLocal', 'U.S. Office of Special Counsel – Hatch Act', '2026-05-14', 'static', 'official_source_direct', 'State and local government employees', 'batch_2026-05-14T16-47-34_indiana_full_v1'),
  ('c721f977c9fadd95', 'IN', '["federal","state","county","municipal"]', 'runoff_rules', 'How are election contests adjudicated in Indiana?', '["Contesting an election result IN","Who hears election fraud disputes?","Challenging vote totals in Indiana"]', 'Under IC 3-12-11, a candidate may file a petition for a recount or an election contest based on specific statutory grounds such as fraud, illegal votes, or tabulation errors. Election contests are formally adjudicated through the civil court system.', 'https://iga.in.gov/laws/2023/ic/titles/3#3-12-11', 'Indiana Code § 3-12-11', '2026-05-14', 'static', 'statute_citation', 'Candidates and Legal Counsel', 'batch_2026-05-14T16-47-34_indiana_full_v1'),
  ('bcaa32e86cbeea19', 'IN', '["federal","state","county","municipal"]', 'runoff_rules', 'What is the threshold for a candidate to request an election recount in Indiana?', '["Automatic recount margin Indiana","When is a recount required by law in IN?","Recount request process IN"]', 'Indiana does not have automatic recounts. A candidate can request a recount by filing a petition and paying a deposit. The deposit is refunded if the recount alters the election result. A candidate can request a recount regardless of the margin.', 'https://iga.in.gov/laws/2023/ic/titles/3#3-12-11', 'Indiana Code § 3-12-11', '2026-05-14', 'static', 'statute_citation', 'Candidates and Legal Counsel', 'batch_2026-05-14T16-47-34_indiana_full_v1')
